"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[109],{9499:e=>{e.exports=JSON.parse('{"functions":[{"name":"Print","desc":"Print a line of normal output. `Success`, `Warn`, `Err`, `Info`, `Hint` and `Reply` are the\\nsame but route to their own theme groups.\\n\\t","params":[{"name":"message","desc":"","lua_type":"any"}],"returns":[],"function_type":"method","source":{"line":198,"path":"src/Context/init.luau"}},{"name":"Return","desc":"Push return values into the pool, matched positionally to the command\'s `Returns` schema.\\nThese feed `/` references, pipelines (`a | b`), and `Karet.Run`\'s result. Nils are preserved.\\n\\t","params":[{"name":"...","desc":"","lua_type":"any"}],"returns":[],"function_type":"method","source":{"line":236,"path":"src/Context/init.luau"}},{"name":"Abort","desc":"Cancel the handler mid-run with a message. The command\'s result becomes `{ ok = false }`,\\nso chains (`a && b`) see the failure. Unwinds cleanly via a tagged error.\\n\\t","params":[{"name":"message","desc":"","lua_type":"string?"}],"returns":[],"function_type":"method","source":{"line":273,"path":"src/Context/init.luau"}}],"properties":[{"name":"Args","desc":"The resolved, type-checked positional arguments, keyed by name.\\n\\t","lua_type":"{ [string]: any }","source":{"line":147,"path":"src/Context/init.luau"}},{"name":"Flags","desc":"Boolean toggles set with `-s` / `-p`.\\n\\t","lua_type":"{ [string]: boolean }","source":{"line":152,"path":"src/Context/init.luau"}},{"name":"Modifiers","desc":"Valued long options: `--reason=spam` -> `ctx.Modifiers.reason`.\\n\\t","lua_type":"{ [string]: any }","source":{"line":157,"path":"src/Context/init.luau"}},{"name":"Input","desc":"The piped value from the previous command in a pipeline (`a | b`), or nil.\\n\\t","lua_type":"any","source":{"line":162,"path":"src/Context/init.luau"}},{"name":"Player","desc":"The calling player (nil in Studio / no-player contexts).\\n\\t","lua_type":"Player?","source":{"line":167,"path":"src/Context/init.luau"}},{"name":"UI","desc":"The rich-output toolkit: `ctx.UI.Table{}`, `ctx.UI.Toast()`, `ctx.UI.Link()`, ... A no-op\\noff the terminal.\\n\\t","lua_type":"{ [string]: any }","source":{"line":173,"path":"src/Context/init.luau"}}],"types":[],"name":"Context","desc":"The `ctx` object passed to every command handler. It carries the resolved input (`Args`,\\n`Flags`, `Modifiers`, `Input`), themed output methods (`Print`, `Success`, `Err`, ...), the\\nreturn pool (`Return`), and the rich surfaces (`UI`, `Window`, `Indicator`).\\n\\n```lua\\nOn = { Server = function(ctx)\\n    local who = ctx.Args.who\\n    if ctx.Flags.silent then return end\\n    ctx.Success(`hi {who.Name}`)\\n    ctx.Return(who)\\nend }\\n```","source":{"line":25,"path":"src/Context/init.luau"}}')}}]);